-- 2026-06-15_basics_guide_content.sql
-- Phase 0 of the Beginners Guide "DB-as-source-of-truth" refactor.
--
-- Adds content_json.reference.guide to the Lesson 0 (slug='basics') row: the
-- canonical, structured linguistic content the 4-step guide flow + /guide/chart
-- now render from. Mirrors the curated view-models previously hardcoded in
-- constants/guide.ts (which is demoted to an offline fallback). Includes the
-- consonant fixes: ಠ Tta, ಢ Dda, ಣ Nna, ಥ tha (Thailand), ವ va (van), ಳ palate.
--
-- Idempotent: jsonb_set replaces reference.guide and leaves the rest of
-- content_json (reference.sections / words / phrases / source) untouched.
-- Manual-run: paste into the Supabase SQL editor (no CLI in this project).

update public.lessons
set content_json = jsonb_set(
  content_json,
  '{reference,guide}',
  $guide${"principles":[{"title":"Say what you see","body":"Kannada is written the way it sounds. Read the letters left to right and you have said the word."},{"title":"Capitals curl your tongue","body":"A capital letter in our spellings (Ta, Da, La) means curl your tongue up and back — a fuller, hollow sound."},{"title":"Doubled letters linger","body":"A doubled consonant (appa, haLLi) is just held a beat longer than a single one."}],"vowelPairs":[{"short":{"kannada":"ಅ","transliteration":"a","example":"up"},"long":{"kannada":"ಆ","transliteration":"ā","example":"art"}},{"short":{"kannada":"ಇ","transliteration":"i","example":"igloo"},"long":{"kannada":"ಈ","transliteration":"ī","example":"seed"}},{"short":{"kannada":"ಉ","transliteration":"u","example":"push"},"long":{"kannada":"ಊ","transliteration":"ū","example":"moon"}},{"short":{"kannada":"ಎ","transliteration":"e","example":"cake"},"long":{"kannada":"ಏ","transliteration":"ē","example":"crane"}},{"short":{"kannada":"ಒ","transliteration":"o","example":"opener"},"long":{"kannada":"ಓ","transliteration":"ō","example":"groan"}}],"vowelLoners":[{"kannada":"ಋ","transliteration":"ru","example":"rupees"},{"kannada":"ಐ","transliteration":"ai","example":"ice"},{"kannada":"ಔ","transliteration":"au","example":"owl"}],"consonantFamilies":[{"id":"throat","place":"Throat","hint":"Sound starts at the back of the mouth.","glyphs":[{"kannada":"ಕ","transliteration":"ka"},{"kannada":"ಖ","transliteration":"kha"},{"kannada":"ಗ","transliteration":"ga"},{"kannada":"ಘ","transliteration":"gha"}]},{"id":"palate","place":"Palate","hint":"Tongue presses the roof of the mouth.","glyphs":[{"kannada":"ಚ","transliteration":"cha"},{"kannada":"ಜ","transliteration":"ja"}]},{"id":"curled","place":"Curled tongue","hint":"Tongue curls up and back (the capital sounds).","glyphs":[{"kannada":"ಟ","transliteration":"Ta"},{"kannada":"ಡ","transliteration":"Da"},{"kannada":"ಣ","transliteration":"Nna"}]},{"id":"teeth","place":"Teeth","hint":"Tongue tip touches the upper teeth (the lowercase sounds).","glyphs":[{"kannada":"ತ","transliteration":"ta"},{"kannada":"ದ","transliteration":"da"},{"kannada":"ನ","transliteration":"na"}]},{"id":"lips","place":"Lips","hint":"Both lips come together.","glyphs":[{"kannada":"ಪ","transliteration":"pa"},{"kannada":"ಬ","transliteration":"ba"},{"kannada":"ಮ","transliteration":"ma"}]}],"readingRows":[{"symbol":"Ta","isCapital":true,"example":"as in Top"},{"symbol":"ta","isCapital":false,"example":"as in Bharath"},{"symbol":"Da","isCapital":true,"example":"as in Dark"},{"symbol":"da","isCapital":false,"example":"as in the"}],"tryIt":{"transliteration":"haLLi","kannada":"ಹಳ್ಳಿ","english":"village"},"chart":[{"kannada":"ಕ","transliteration":"ka","example":"as in cup"},{"kannada":"ಖ","transliteration":"kha","example":"as in khadi"},{"kannada":"ಗ","transliteration":"ga","example":"as in gun"},{"kannada":"ಘ","transliteration":"gha","example":"as in ghat"},{"kannada":"ಙ","transliteration":"gna","example":"as in gnome"},{"kannada":"ಚ","transliteration":"cha","example":"as in chair"},{"kannada":"ಛ","transliteration":"chha","example":"as in church"},{"kannada":"ಜ","transliteration":"ja","example":"as in jug"},{"kannada":"ಝ","transliteration":"jha","example":"as in badge"},{"kannada":"ಞ","transliteration":"nja","example":"rare in English"},{"kannada":"ಟ","transliteration":"Ta","example":"as in Top"},{"kannada":"ಠ","transliteration":"Tta","example":"hard 'Tt' — as in cut"},{"kannada":"ಡ","transliteration":"Da","example":"as in Dark"},{"kannada":"ಢ","transliteration":"Dda","example":"hard 'Dd' — as in board"},{"kannada":"ಣ","transliteration":"Nna","example":"heavy 'Nn' — rare in English"},{"kannada":"ತ","transliteration":"ta","example":"as in Bharath"},{"kannada":"ಥ","transliteration":"tha","example":"soft 'th' — as in Thailand"},{"kannada":"ದ","transliteration":"da","example":"as in the"},{"kannada":"ಧ","transliteration":"dha","example":"as in dhal"},{"kannada":"ನ","transliteration":"na","example":"as in can"},{"kannada":"ಪ","transliteration":"pa","example":"as in papaya"},{"kannada":"ಫ","transliteration":"pha","example":"as in orphan"},{"kannada":"ಬ","transliteration":"ba","example":"as in balloon"},{"kannada":"ಭ","transliteration":"bha","example":"as in Bharath"},{"kannada":"ಮ","transliteration":"ma","example":"as in man"},{"kannada":"ಯ","transliteration":"ya","example":"as in yak"},{"kannada":"ರ","transliteration":"ra","example":"as in rat"},{"kannada":"ಲ","transliteration":"la","example":"as in lamp"},{"kannada":"ವ","transliteration":"va","example":"as in van"},{"kannada":"ಶ","transliteration":"sha","example":"as in ash"},{"kannada":"ಷ","transliteration":"sshha","example":"as in shut"},{"kannada":"ಸ","transliteration":"sa","example":"as in sun"},{"kannada":"ಹ","transliteration":"ha","example":"as in hump"},{"kannada":"ಳ","transliteration":"lla","example":"rare 'L' — palate sound"}]}$guide$::jsonb,
  true
)
where slug = 'basics';
